import React, { useState } from 'react';

export default function App() {
  const [desc, setDesc] = useState('');
  const [loading, setLoading] = useState(false);

  async function handleGenerate(e) {
    e.preventDefault();
    setLoading(true);
    try {
      const res = await fetch('/api/generate', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ description: desc })
      });
      if (!res.ok) {
        const err = await res.json();
        alert("Error: " + (err.error || JSON.stringify(err)));
        setLoading(false);
        return;
      }
      // get blob and download
      const blob = await res.blob();
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'resume.pdf';
      a.click();
      URL.revokeObjectURL(url);
    } catch (err) {
      alert('Error: ' + err.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div style={{ padding: 24, fontFamily: 'Arial, sans-serif' }}>
      <h1>Auto Resume Builder</h1>
      <p>Paste your description or job details below; the builder will fill the yellow highlighted areas and return a PDF matching your template.</p>
      <form onSubmit={handleGenerate}>
        <textarea
          value={desc}
          onChange={(e) => setDesc(e.target.value)}
          placeholder="Write your full resume description here (education, jobs, skills, contact)."
          rows={12}
          style={{ width: '100%', padding: 12 }}
        />
        <div style={{ marginTop:12 }}>
          <button type="submit" disabled={loading}>{loading ? 'Generating...' : 'Generate PDF'}</button>
        </div>
      </form>
    </div>
  );
}
